     1→import { existsSync, mkdirSync, unlinkSync, writeFileSync, readFileSync } from "node:fs";
     2→import { join } from "node:path";
     3→import { randomBytes, createHash } from "node:crypto";
     4→import { findGitRoot, saveRepoConfig, saveGlobalConfig, loadGlobalConfig, loadConfig } from "../config";
     5→import { OsabioHttpClient } from "../http-client";
     6→import { generateDPoPKeyMaterial } from "../dpop";
     7→import { mergeProxyEnvSettings, checkSettingsGitignored } from "../proxy-settings";
     8→import {
     9→  OSABIO_HOOKS,
    10→  OSABIO_CLAUDE_MD,
    11→  OSABIO_COMMANDS,
    12→} from "./init-content";
    13→
    14→const DEFAULT_SERVER_URL = "http://localhost:3000";
    15→
    16→export async function runInit(): Promise<void> {
    17→  const serverUrl = process.env.OSABIO_SERVER_URL ?? DEFAULT_SERVER_URL;
    18→  const workspaceId = process.env.OSABIO_WORKSPACE_ID;
    19→
    20→  const gitRoot = findGitRoot(process.cwd());
    21→  if (!gitRoot) {
    22→    console.error("Not inside a git repository. Run osabio init from a project directory.");
    23→    process.exit(1);
    24→  }
    25→
    26→  if (!workspaceId) {
    27→    console.error("Set OSABIO_WORKSPACE_ID env var to your workspace ID.");
    28→    console.error("Find it in the Osabio web UI or the database.");
    29→    process.exit(1);
    30→  }
    31→
    32→  console.log("Osabio Init\n───────────\n");
    33→
    34→  // Step 1: Auth
    35→  await setupAuth(serverUrl, workspaceId, gitRoot);
    36→
    37→  // Step 2: .mcp.json
    38→  await setupMcpJson(gitRoot);
    39→
    40→  // Step 3: .claude/settings.json hooks
    41→  await setupClaudeHooks(gitRoot);
    42→
    43→  // Step 4: CLAUDE.md
    44→  await setupClaudeMd(gitRoot);
    45→
    46→  // Step 5: Commands
    47→  await setupCommands(gitRoot);
    48→
    49→  // Step 6: Git hooks
    50→  installGitHooks(gitRoot);
    51→
    52→  // Step 7: Proxy config
    53→  await setupProxyConfig(serverUrl, workspaceId, gitRoot);
    54→
    55→  console.log(`\nDone. Restart Claude Code to activate.`);
    56→}
    57→
    58→// ---------------------------------------------------------------------------
    59→// Step 1: Auth (OAuth 2.1 PKCE)
    60→// ---------------------------------------------------------------------------
    61→
    62→const DEFAULT_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
    63→const DEFAULT_AUTH_CALLBACK_TIMEOUT_MS = 300_000;
    64→
    65→type SetupAuthOptions = {
    66→  openUrl?: (url: string) => void | Promise<void>;
    67→  callbackTimeoutMs?: number;
    68→};
    69→
    70→function base64url(buf: Buffer): string {
    71→  return buf.toString("base64url");
    72→}
    73→
    74→function generatePkce(): { verifier: string; challenge: string } {
    75→  const verifier = base64url(randomBytes(32));
    76→  const challenge = base64url(createHash("sha256").update(verifier).digest());
    77→  return { verifier, challenge };
    78→}
    79→
    80→export async function setupAuth(
    81→  serverUrl: string,
    82→  workspaceId: string,
    83→  gitRoot: string,
    84→  options?: SetupAuthOptions,
    85→): Promise<void> {
    86→  const oauthResource = serverUrl.replace(/\/$/, "");
    87→  const global = await loadGlobalConfig();
    88→  const existing = global?.repos[gitRoot];
    89→  if (existing && existing.workspace === workspaceId && existing.access_token) {
    90→    console.log(`✓ Auth: already configured for ${gitRoot}`);
    91→    return;
    92→  }
    93→
    94→  // 1. Verify workspace exists
    95→  try {
    96→    await OsabioHttpClient.listProjects(serverUrl, workspaceId);
    97→  } catch {
    98→    console.error(`Workspace ${workspaceId} not found on ${serverUrl}`);
    99→    process.exit(1);
   100→  }
   101→
   102→  // 2. PKCE
   103→  const pkce = generatePkce();
   104→  const state = base64url(randomBytes(16));
   105→
   106→  // 3. Start local callback server
   107→  const { promise: codePromise, resolve: resolveCode, reject: rejectCode } = Promise.withResolvers<string>();
   108→
   109→  const callbackServer = Bun.serve({
   110→    port: 0,
   111→    hostname: "127.0.0.1",
   112→    routes: {
   113→      "/callback": (request) => {
   114→        const url = new URL(request.url);
   115→        const code = url.searchParams.get("code");
   116→        const returnedState = url.searchParams.get("state");
   117→        const error = url.searchParams.get("error");
   118→
   119→        if (error) {
   120→          rejectCode(new Error(`OAuth error: ${error}`));
   121→          return new Response("<html><body><h1>Authentication failed</h1><p>You can close this tab.</p></body></html>", {
   122→            headers: { "Content-Type": "text/html" },
   123→          });
   124→        }
   125→        if (returnedState !== state) {
   126→          rejectCode(new Error("state mismatch"));
   127→          return new Response("<html><body><h1>State mismatch</h1></body></html>", {
   128→            headers: { "Content-Type": "text/html" },
   129→          });
   130→        }
   131→        if (!code) {
   132→          rejectCode(new Error("no code returned"));
   133→          return new Response("<html><body><h1>No authorization code</h1></body></html>", {
   134→            headers: { "Content-Type": "text/html" },
   135→          });
   136→        }
   137→
   138→        resolveCode(code);
   139→        return new Response("<html><body><h1>Authenticated!</h1><p>You can close this tab and return to the terminal.</p></body></html>", {
   140→          headers: { "Content-Type": "text/html" },
   141→        });
   142→      },
   143→    },
   144→  });
   145→
   146→  const redirectUri = `http://127.0.0.1:${callbackServer.port}/callback`;
   147→
   148→  // 4. Dynamic Client Registration
   149→  const dcrRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
   150→    method: "POST",
   151→    headers: { "Content-Type": "application/json" },
   152→    body: JSON.stringify({
   153→      client_name: `osabio-cli-${workspaceId.slice(0, 8)}`,
   154→      redirect_uris: [redirectUri],
   155→      grant_types: ["authorization_code", "refresh_token"],
   156→      response_types: ["code"],
   157→      token_endpoint_auth_method: "none",
   158→    }),
   159→  });
   160→  if (!dcrRes.ok) {
   161→    callbackServer.stop();
   162→    throw new Error(`Client registration failed: ${dcrRes.status} ${await dcrRes.text()}`);
   163→  }
   164→  const dcr = await dcrRes.json() as { client_id: string };
   165→  const actualClientId = dcr.client_id;
   166→
   167→  // 5. Open browser
   168→  const authUrl = new URL(`${serverUrl}/api/auth/oauth2/authorize`);
   169→  authUrl.searchParams.set("client_id", actualClientId);
   170→  authUrl.searchParams.set("redirect_uri", redirectUri);
   171→  authUrl.searchParams.set("response_type", "code");
   172→  authUrl.searchParams.set("scope", DEFAULT_SCOPES);
   173→  authUrl.searchParams.set("code_challenge", pkce.challenge);
   174→  authUrl.searchParams.set("code_challenge_method", "S256");
   175→  authUrl.searchParams.set("state", state);
   176→  // Pass resource so better-auth issues a JWT access token (not opaque)
   177→  authUrl.searchParams.set("resource", oauthResource);
   178→
   179→  console.log("Opening browser for authentication...");
   180→  console.log(`If the browser doesn't open, visit: ${authUrl.toString()}\n`);
   181→
   182→  const openUrl = options?.openUrl ?? ((url: string) => {
   183→    const openCmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
   184→    Bun.spawn([openCmd, url], { stdout: "ignore", stderr: "ignore" });
   185→  });
   186→  await openUrl(authUrl.toString());
   187→
   188→  // 6. Wait for callback
   189→  let code: string;
   190→  let callbackTimeoutHandle: ReturnType<typeof setTimeout> | undefined;
   191→  const callbackTimeoutMs = options?.callbackTimeoutMs ?? DEFAULT_AUTH_CALLBACK_TIMEOUT_MS;
   192→  const callbackOrTimeout = new Promise<string>((resolve, reject) => {
   193→    callbackTimeoutHandle = setTimeout(() => {
   194→      reject(
   195→        new Error(
   196→          `Timed out waiting for OAuth callback on ${redirectUri}. Complete browser auth, then retry osabio init.`,
   197→        ),
   198→      );
   199→    }, callbackTimeoutMs);
   200→
   201→    codePromise.then(resolve).catch(reject);
   202→  });
   203→
   204→  try {
   205→    code = await callbackOrTimeout;
   206→  } catch (error) {
   207→    callbackServer.stop();
   208→    throw error;
   209→  } finally {
   210→    if (callbackTimeoutHandle) clearTimeout(callbackTimeoutHandle);
   211→  }
   212→
   213→  // 7. Exchange code for tokens
   214→  const tokenRes = await fetch(`${serverUrl}/api/auth/oauth2/token`, {
   215→    method: "POST",
   216→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
   217→    body: new URLSearchParams({
   218→      grant_type: "authorization_code",
   219→      code,
   220→      redirect_uri: redirectUri,
   221→      client_id: actualClientId,
   222→      code_verifier: pkce.verifier,
   223→      resource: oauthResource,
   224→    }),
   225→  });
   226→
   227→  callbackServer.stop();
   228→
   229→  if (!tokenRes.ok) {
   230→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
   231→  }
   232→
   233→  const tokens = await tokenRes.json() as {
   234→    access_token: string;
   235→    refresh_token: string;
   236→    expires_in: number;
   237→    token_type: string;
   238→  };
   239→
   240→  // 8. Generate DPoP key material for sender-constrained tokens
   241→  const dpopMaterial = await generateDPoPKeyMaterial();
   242→
   243→  // 9. Discover workspace owner identity for intent submission
   244→  let identityId: string | undefined;
   245→  try {
   246→    const identityRes = await fetch(`${serverUrl}/api/auth/identity/${workspaceId}`);
   247→    if (identityRes.ok) {
   248→      const identityData = await identityRes.json() as { identity_id: string };
   249→      identityId = identityData.identity_id;
   250→    }
   251→  } catch {
   252→    // Identity discovery is optional during init — will be retried lazily
   253→  }
   254→
   255→  // 10. Store tokens + DPoP key material
   256→  await saveRepoConfig(serverUrl, gitRoot, {
   257→    workspace: workspaceId,
   258→    client_id: actualClientId,
   259→    access_token: tokens.access_token,
   260→    refresh_token: tokens.refresh_token,
   261→    token_expires_at: Math.floor(Date.now() / 1000) + tokens.expires_in,
   262→    dpop_private_jwk: dpopMaterial.privateJwk,
   263→    dpop_public_jwk: dpopMaterial.publicJwk,
   264→    dpop_thumbprint: dpopMaterial.thumbprint,
   265→    identity_id: identityId,
   266→  });
   267→
   268→  console.log(`✓ Auth: OAuth tokens + DPoP key pair saved for ${gitRoot}`);
   269→  if (identityId) {
   270→    console.log(`✓ Identity: ${identityId}`);
   271→  }
   272→}
   273→
   274→// ---------------------------------------------------------------------------
   275→// Step 2: .mcp.json
   276→// ---------------------------------------------------------------------------
   277→
   278→export async function setupMcpJson(gitRoot: string): Promise<void> {
   279→  const mcpPath = join(gitRoot, ".mcp.json");
   280→  const file = Bun.file(mcpPath);
   281→  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
   282→
   283→  if (await file.exists()) {
   284→    try {
   285→      mcp = await file.json();
   286→      mcp.mcpServers ??= {};
   287→    } catch {
   288→      // Corrupted file — overwrite
   289→    }
   290→  }
   291→
   292→  mcp.mcpServers.osabio = { command: "osabio", args: ["mcp"] };
   293→  await Bun.write(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
   294→  console.log("✓ MCP: .mcp.json updated");
   295→}
   296→
   297→// ---------------------------------------------------------------------------
   298→// Step 3: .claude/settings.json hooks
   299→// ---------------------------------------------------------------------------
   300→
   301→type HookEntry = { type: string; command?: string; prompt?: string };
   302→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
   303→
   304→export async function setupClaudeHooks(gitRoot: string): Promise<void> {
   305→  const claudeDir = join(gitRoot, ".claude");
   306→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
   307→
   308→  const settingsPath = join(claudeDir, "settings.json");
   309→  const file = Bun.file(settingsPath);
   310→  let settings: Record<string, unknown> = {};
   311→
   312→  if (await file.exists()) {
   313→    try {
   314→      settings = await file.json();
   315→    } catch {
   316→      // Corrupted — start fresh
   317→    }
   318→  }
   319→
   320→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
   321→  let added = 0;
   322→
   323→  for (const [event, hookDefs] of Object.entries(OSABIO_HOOKS)) {
   324→    hooks[event] ??= [];
   325→
   326→    const hasOsabio = hooks[event].some((group) =>
   327→      group.hooks?.some(
   328→        (h) => h.command?.startsWith("osabio ") || h.prompt?.includes("Osabio MCP"),
   329→      ),
   330→    );
   331→
   332→    if (!hasOsabio) {
   333→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
   334→      added++;
   335→    }
   336→  }
   337→
   338→  settings.hooks = hooks;
   339→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
   340→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
   341→}
   342→
   343→// ---------------------------------------------------------------------------
   344→// Step 4: CLAUDE.md
   345→// ---------------------------------------------------------------------------
   346→
   347→export const MARKER_START = "<!-- osabio-plugin-start -->";
   348→export const MARKER_END = "<!-- osabio-plugin-end -->";
   349→
   350→export async function setupClaudeMd(gitRoot: string): Promise<void> {
   351→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
   352→  const file = Bun.file(claudeMdPath);
   353→  let content = "";
   354→
   355→  if (await file.exists()) {
   356→    content = await file.text();
   357→  }
   358→
   359→  const osabioBlock = `${MARKER_START}\n${OSABIO_CLAUDE_MD}\n${MARKER_END}`;
   360→
   361→  const startIdx = content.indexOf(MARKER_START);
   362→  const endIdx = content.indexOf(MARKER_END);
   363→
   364→  if (startIdx !== -1 && endIdx !== -1) {
   365→    content = content.slice(0, startIdx) + osabioBlock + content.slice(endIdx + MARKER_END.length);
   366→  } else {
   367→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
   368→    content = content + separator + osabioBlock + "\n";
   369→  }
   370→
   371→  await Bun.write(claudeMdPath, content);
   372→  console.log("✓ CLAUDE.md: Osabio plugin instructions added");
   373→}
   374→
   375→// ---------------------------------------------------------------------------
   376→// Step 6: Git hooks
   377→// ---------------------------------------------------------------------------
   378→
   379→export function installGitHooks(gitRoot?: string): void {
   380→  const root = gitRoot ?? findGitRoot(process.cwd());
   381→  if (!root) {
   382→    console.log("  No .git directory found — skipping git hook installation.");
   383→    return;
   384→  }
   385→
   386→  const hooksDir = join(root, ".git", "hooks");
   387→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
   388→
   389→  const preCommitPath = join(hooksDir, "pre-commit");
   390→  const postCommitPath = join(hooksDir, "post-commit");
   391→  const preCommitScript = `#!/bin/sh
   392→# Osabio pre-commit hook: check for task completion and unlogged decisions
   393→osabio check-commit
   394→`;
   395→  const postCommitScript = `#!/bin/sh
   396→# Osabio post-commit hook: fire-and-forget commit-check
   397→osabio commit-check &
   398→exit 0
   399→`;
   400→
   401→  if (!existsSync(preCommitPath)) {
   402→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
   403→    console.log("✓ Git: pre-commit hook installed");
   404→  } else {
   405→    console.log("✓ Git: pre-commit hook already exists");
   406→  }
   407→
   408→  // Remove legacy Osabio post-commit hook, then install new one
   409→  if (existsSync(postCommitPath)) {
   410→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
   411→    const isLegacyOsabio =
   412→      postCommitContent.includes("Osabio post-commit hook") &&
   413→      postCommitContent.includes("osabio log-commit");
   414→    const isCurrentOsabio =
   415→      postCommitContent.includes("Osabio post-commit hook") &&
   416→      postCommitContent.includes("osabio commit-check");
   417→    if (isLegacyOsabio) {
   418→      unlinkSync(postCommitPath);
   419→      console.log("  Removed legacy Osabio post-commit hook");
   420→    } else if (isCurrentOsabio) {
   421→      console.log("✓ Git: post-commit hook already exists");
   422→      return;
   423→    } else {
   424→      // Non-osabio hook — leave it alone
   425→      console.log("✓ Git: post-commit hook already exists (non-osabio)");
   426→      return;
   427→    }
   428→  }
   429→
   430→  writeFileSync(postCommitPath, postCommitScript, { mode: 0o755 });
   431→  console.log("✓ Git: post-commit hook installed");
   432→}
   433→
   434→// ---------------------------------------------------------------------------
   435→// Step 7: Proxy config (.claude/settings.local.json + ~/.osabio/config.json)
   436→// ---------------------------------------------------------------------------
   437→
   438→export async function setupProxyConfig(
   439→  serverUrl: string,
   440→  workspaceId: string,
   441→  gitRoot: string,
   442→): Promise<void> {
   443→  // 1. Load existing config to get access_token
   444→  const config = await loadConfig();
   445→  if (!config?.access_token) {
   446→    console.log("  Skipping proxy setup — no access token available.");
   447→    return;
   448→  }
   449→
   450→  // 2. Request proxy token from server
   451→  let proxyToken: string;
   452→  let proxyTokenExpiresAt: string;
   453→  try {
   454→    const res = await fetch(`${serverUrl}/api/auth/proxy-token`, {
   455→      method: "POST",
   456→      headers: {
   457→        "Content-Type": "application/json",
   458→        Authorization: `Bearer ${config.access_token}`,
   459→      },
   460→      body: JSON.stringify({ workspace_id: workspaceId }),
   461→    });
   462→    if (!res.ok) {
   463→      const body = await res.text();
   464→      console.log(`  Skipping proxy setup — proxy token request failed: ${res.status} ${body}`);
   465→      return;
   466→    }
   467→    const data = (await res.json()) as {
   468→      proxy_token: string;
   469→      expires_at: string;
   470→    };
   471→    proxyToken = data.proxy_token;
   472→    proxyTokenExpiresAt = data.expires_at;
   473→  } catch (err) {
   474→    console.log(`  Skipping proxy setup — could not reach proxy token endpoint.`);
   475→    return;
   476→  }
   477→
   478→  // 3. Store proxy token expiry in ~/.osabio/config.json (raw token stays only in settings.local.json)
   479→  const global = await loadGlobalConfig();
   480→  if (global?.repos[gitRoot]) {
   481→    delete global.repos[gitRoot].proxy_token;
   482→    global.repos[gitRoot].proxy_token_expires_at = proxyTokenExpiresAt;
   483→    await saveGlobalConfig(global);
   484→  } else {
   485→    console.warn(`  Warning: repo entry for ${gitRoot} not found in ~/.osabio/config.json — proxy token expiry tracking will not work.`);
   486→  }
   487→
   488→  // 4. Read or create .claude/settings.local.json
   489→  const claudeDir = join(gitRoot, ".claude");
   490→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
   491→
   492→  const settingsPath = join(claudeDir, "settings.local.json");
   493→  const settingsFile = Bun.file(settingsPath);
   494→  let existing: Record<string, unknown> = {};
   495→  if (await settingsFile.exists()) {
   496→    try {
   497→      existing = await settingsFile.json();
   498→    } catch {
   499→      // Corrupted — start fresh
   500→    }
   501→  }
   502→
   503→  // 5. Merge proxy env vars (pure function)
   504→  const merged = mergeProxyEnvSettings(existing, serverUrl, proxyToken);
   505→
   506→  // 6. Write merged config
   507→  await Bun.write(settingsPath, JSON.stringify(merged, undefined, 2) + "\n");
   508→
   509→  // 7. Check .gitignore
   510→  const gitignorePath = join(gitRoot, ".gitignore");
   511→  let gitignoreContent: string | undefined;
   512→  try {
   513→    const gitignoreFile = Bun.file(gitignorePath);
   514→    if (await gitignoreFile.exists()) {
   515→      gitignoreContent = await gitignoreFile.text();
   516→    }
   517→  } catch {
   518→    // No .gitignore — that's fine
   519→  }
   520→
   521→  if (!checkSettingsGitignored(gitignoreContent)) {
   522→    console.log(
   523→      "  ⚠ Warning: .claude/settings.local.json is not in .gitignore — it contains a secret proxy token.",
   524→    );
   525→  }
   526→
   527→  // 8. Confirmation
   528→  const expiryDate = new Date(proxyTokenExpiresAt).toLocaleDateString();
   529→  console.log(`✓ Proxy: .claude/settings.local.json configured`);
   530→  console.log(`  Base URL: ${serverUrl}/proxy/llm/anthropic`);
   531→  console.log(`  Token expires: ${expiryDate}`);
   532→}
   533→
   534→export async function setupCommands(gitRoot: string): Promise<void> {
   535→  const commandsDir = join(gitRoot, ".claude", "commands");
   536→  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
   537→
   538→  let count = 0;
   539→  for (const [filename, content] of Object.entries(OSABIO_COMMANDS)) {
   540→    await Bun.write(join(commandsDir, filename), content + "\n");
   541→    count++;
   542→  }
   543→
   544→  console.log(`✓ Commands: ${count} slash commands installed to .claude/commands/`);
   545→}
