   229→  if (!tokenRes.ok) {
   230→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
   231→  }
   232→
   233→  const tokens = await tokenRes.json() as {
   234→    access_token: string;
   235→    refresh_token: string;
   236→    expires_in: number;
   237→    token_type: string;
   238→  };
   239→
   240→  // 8. Generate DPoP key material for sender-constrained tokens
   241→  const dpopMaterial = await generateDPoPKeyMaterial();
   242→
   243→  // 9. Discover workspace owner identity for intent submission
