   257→    workspace: workspaceId,
   258→    client_id: actualClientId,
   259→    access_token: tokens.access_token,
   260→    refresh_token: tokens.refresh_token,
   261→    token_expires_at: Math.floor(Date.now() / 1000) + tokens.expires_in,
   262→    dpop_private_jwk: dpopMaterial.privateJwk,
   263→    dpop_public_jwk: dpopMaterial.publicJwk,
   264→    dpop_thumbprint: dpopMaterial.thumbprint,
   265→    identity_id: identityId,
   266→  });
   267→
   268→  console.log(`✓ Auth: OAuth tokens + DPoP key pair saved for ${gitRoot}`);
   269→  if (identityId) {
