   379→export function installGitHooks(gitRoot?: string): void {
   380→  const root = gitRoot ?? findGitRoot(process.cwd());
   381→  if (!root) {
   382→    console.log("  No .git directory found — skipping git hook installation.");
   383→    return;
   384→  }
   385→
   386→  const hooksDir = join(root, ".git", "hooks");
   387→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
   388→
   389→  const preCommitPath = join(hooksDir, "pre-commit");
   390→  const postCommitPath = join(hooksDir, "post-commit");
   391→  const preCommitScript = `#!/bin/sh
   392→# Osabio pre-commit hook: check for task completion and unlogged decisions
   393→osabio check-commit
   394→`;
   395→  const postCommitScript = `#!/bin/sh
   396→# Osabio post-commit hook: fire-and-forget commit-check
   397→osabio commit-check &
   398→exit 0
   399→`;
   400→
   401→  if (!existsSync(preCommitPath)) {
   402→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
   403→    console.log("✓ Git: pre-commit hook installed");
   404→  } else {
   405→    console.log("✓ Git: pre-commit hook already exists");
   406→  }
   407→
   408→  // Remove legacy Osabio post-commit hook, then install new one
   409→  if (existsSync(postCommitPath)) {
   410→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
   411→    const isLegacyOsabio =
   412→      postCommitContent.includes("Osabio post-commit hook") &&
   413→      postCommitContent.includes("osabio log-commit");
   414→    const isCurrentOsabio =
   415→      postCommitContent.includes("Osabio post-commit hook") &&
   416→      postCommitContent.includes("osabio commit-check");
   417→    if (isLegacyOsabio) {
   418→      unlinkSync(postCommitPath);
   419→      console.log("  Removed legacy Osabio post-commit hook");
   420→    } else if (isCurrentOsabio) {
   421→      console.log("✓ Git: post-commit hook already exists");
   422→      return;
   423→    } else {
   424→      // Non-osabio hook — leave it alone
   425→      console.log("✓ Git: post-commit hook already exists (non-osabio)");
   426→      return;
   427→    }
   428→  }
   429→
   430→  writeFileSync(postCommitPath, postCommitScript, { mode: 0o755 });
   431→  console.log("✓ Git: post-commit hook installed");
   432→}
