   438→export async function setupProxyConfig(
   439→  serverUrl: string,
   440→  workspaceId: string,
   441→  gitRoot: string,
   442→): Promise<void> {
   443→  // 1. Load existing config to get access_token
   444→  const config = await loadConfig();
   445→  if (!config?.access_token) {
   446→    console.log("  Skipping proxy setup — no access token available.");
   447→    return;
   448→  }
   449→
   450→  // 2. Request proxy token from server
   451→  let proxyToken: string;
   452→  let proxyTokenExpiresAt: string;
   453→  try {
   454→    const res = await fetch(`${serverUrl}/api/auth/proxy-token`, {
   455→      method: "POST",
   456→      headers: {
   457→        "Content-Type": "application/json",
   458→        Authorization: `Bearer ${config.access_token}`,
   459→      },
   460→      body: JSON.stringify({ workspace_id: workspaceId }),
   461→    });
   462→    if (!res.ok) {
   463→      const body = await res.text();
   464→      console.log(`  Skipping proxy setup — proxy token request failed: ${res.status} ${body}`);
   465→      return;
   466→    }
   467→    const data = (await res.json()) as {
   468→      proxy_token: string;
   469→      expires_at: string;
   470→    };
   471→    proxyToken = data.proxy_token;
   472→    proxyTokenExpiresAt = data.expires_at;
   473→  } catch (err) {
   474→    console.log(`  Skipping proxy setup — could not reach proxy token endpoint.`);
   475→    return;
   476→  }
   477→
   478→  // 3. Store proxy token expiry in ~/.osabio/config.json (raw token stays only in settings.local.json)
   479→  const global = await loadGlobalConfig();
   480→  if (global?.repos[gitRoot]) {
   481→    delete global.repos[gitRoot].proxy_token;
   482→    global.repos[gitRoot].proxy_token_expires_at = proxyTokenExpiresAt;
   483→    await saveGlobalConfig(global);
   484→  } else {
   485→    console.warn(`  Warning: repo entry for ${gitRoot} not found in ~/.osabio/config.json — proxy token expiry tracking will not work.`);
   486→  }
   487→
   488→  // 4. Read or create .claude/settings.local.json
   489→  const claudeDir = join(gitRoot, ".claude");
   490→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
   491→
   492→  const settingsPath = join(claudeDir, "settings.local.json");
   493→  const settingsFile = Bun.file(settingsPath);
   494→  let existing: Record<string, unknown> = {};
   495→  if (await settingsFile.exists()) {
   496→    try {
   497→      existing = await settingsFile.json();
   498→    } catch {
   499→      // Corrupted — start fresh
   500→    }
