  headers: Headers,
  bearerToken: string,
  betterAuthUrl: string,
): Promise<string | undefined> {
  const session = await auth.api.getSession({ headers });
  if (session?.user?.id) {
    return session.user.id;
  }

  // Fallback for CLI OAuth bearer tokens (no browser session cookie).
  // Accept both common audience variants:
  //  - <server base URL>
  //  - <server base URL>/api/auth
  const validatePrimaryAudience = createJwtValidator(betterAuthUrl);
  try {
    const claims = await validatePrimaryAudience(bearerToken);
    if (typeof claims.sub === "string" && claims.sub.length > 0) {
      return claims.sub;
    }
  } catch {
    // Try secondary audience below.
  }

  const authAudience = betterAuthUrl.endsWith("/api/auth")
    ? betterAuthUrl
    : `${betterAuthUrl}/api/auth`;
  if (authAudience === betterAuthUrl) {
    return undefined;
  }

  const validateAuthAudience = createJwtValidator(authAudience);
  try {
    const claims = await validateAuthAudience(bearerToken);
    if (typeof claims.sub === "string" && claims.sub.length > 0) {
      return claims.sub;
    }
  } catch {
    return undefined;
  }

// OAuth 2.1 discovery — proxy root-level .well-known to better-auth handler
"/.well-known/oauth-authorization-server/*": {
  GET: async (request) => deps.auth.handler(request),
},
"/.well-known/oauth-protected-resource": {
  GET: () => jsonResponse({
    resource: config.betterAuthUrl,
    authorization_servers: [config.betterAuthUrl],
    scopes_supported: Object.keys(OSABIO_SCOPES),
    bearer_methods_supported: ["header"],
  }, 200),
},
"/api/auth/oauth-client/:clientId": {
  GET: withTracing(
    "GET /api/auth/oauth-client/:clientId",
